const LessonEngine = ({ weekId, dayId, onComplete, onExit }: { weekId: number, dayId: number, onComplete: () => void, onExit: () => void }) => {
    const lessonData = ALL_CURRICULUM[weekId]?.find(d => d.day === dayId);
    const [steps, setSteps] = useState<LessonStep[]>([]);
    const [stepIndex, setStepIndex] = useState(0);
    const [mistakes, setMistakes] = useState<LessonStep[]>([]);
    const [isReviewMode, setIsReviewMode] = useState(false);
    const [selectedOption, setSelectedOption] = useState<number | null>(null);
    const [showResult, setShowResult] = useState(false);
    const [isCorrect, setIsCorrect] = useState(false);
    const [shake, setShake] = useState(false);
    const [showSensei, setShowSensei] = useState(false);

    useEffect(() => { 
        if (lessonData) {
            setSteps(lessonData.steps || []);
        } 
    }, [lessonData]);

    useEffect(() => { setSelectedOption(null); setShowResult(false); setIsCorrect(false); setShake(false); }, [stepIndex, isReviewMode]);

    if (!steps.length) return <div>加载中...</div>;
    const currentStep = steps[stepIndex];

    const handleCheck = () => {
        if (!showResult && selectedOption !== null) {
            let correct = false;
            if (currentStep.type === 'quiz') {
                correct = selectedOption === currentStep.correct;
            } else if (currentStep.type === 'fill') {
                correct = currentStep.options![selectedOption] === currentStep.correct;
            }

            setIsCorrect(correct); setShowResult(true);
            if (correct) {
                SoundSynth.play('correct');
            } else {
                SoundSynth.play('wrong');
                setShake(true);
                setTimeout(() => setShake(false), 500);
                if (!isReviewMode) setMistakes(prev => [...prev, currentStep]);
            }
        }
    };

    const handleMatchComplete = () => { setIsCorrect(true); setShowResult(true); SoundSynth.play('correct'); };

    const handleContinue = () => {
        SoundSynth.play('pop');
        if (stepIndex < steps.length - 1) setStepIndex(prev => prev + 1);
        else {
            if (!isReviewMode && mistakes.length > 0) { 
                setSteps([...mistakes]); // Use a fresh copy
                setStepIndex(0); 
                setMistakes([]); 
                setIsReviewMode(true); 
            }
            else if (isReviewMode && mistakes.length > 0) { 
                setSteps([...mistakes]); 
                setStepIndex(0); 
                setMistakes([]); 
            }
            else { SoundSynth.play('complete'); onComplete(); }
        }
    };

    const handleBack = () => { if (stepIndex > 0) { SoundSynth.play('click'); setStepIndex(prev => prev - 1); } };

    return (
        <div className="fixed inset-0 bg-white z-50 flex flex-col">
            <div className={`p-4 flex items-center gap-4 ${isReviewMode ? 'bg-orange-100' : ''}`}>
                <div className="flex items-center gap-2">
                    <button onClick={() => { SoundSynth.play('click'); onExit(); }} className="text-gray-400 hover:text-gray-600"><i className="fa-solid fa-xmark text-2xl"></i></button>
                    <button onClick={handleBack} disabled={stepIndex === 0} className={`p-2 rounded-full transition ${stepIndex === 0 ? 'text-gray-200 cursor-not-allowed' : 'text-gray-400 hover:bg-gray-100 hover:text-gray-600'}`} title="回退"><i className="fa-solid fa-arrow-left text-xl"></i></button>
                </div>
                <div className="flex-1">{isReviewMode ? <div className="text-center font-bold text-orange-600 animate-pulse"><i className="fa-solid fa-rotate-left"></i> 错题复习中...</div> : <ProgressBar current={stepIndex + 1} total={steps.length} />}</div>
            </div>
            <div className="flex-1 flex flex-col items-center justify-center p-6 max-w-2xl mx-auto w-full overflow-y-auto">
                {(currentStep.type === 'theory' || currentStep.type === 'boss') && (
                    <div className="text-center animate-slide-up">
                        <h2 className="text-2xl font-bold mb-6 text-gray-800">{currentStep.isBoss ? "终极考验" : "任务简报"}</h2>
                        <div className={`text-lg text-gray-600 leading-relaxed mb-8 border-l-4 pl-4 text-left ${currentStep.isBoss ? 'border-red-600 bg-red-50 p-4' : 'border-orange-400'}`}>{currentStep.content}</div>
                        <div className={`text-6xl mb-8 ${currentStep.isBoss ? 'text-red-600' : 'text-orange-400'} animate-bounce-slight`}><i className={`fa-solid ${currentStep.isBoss ? 'fa-dragon' : 'fa-lightbulb'}`}></i></div>
                    </div>
                )}
                {currentStep.type === 'quiz' && (
                    <div className="w-full animate-slide-up">
                        <h2 className="text-2xl font-bold mb-8 text-gray-800">{currentStep.question}</h2>
                        <div className={`space-y-4 ${shake ? 'animate-shake' : ''}`}>
                            {currentStep.options?.map((opt, idx) => (
                                <button 
                                    key={idx} 
                                    onClick={() => { if (!showResult) { SoundSynth.play('pop'); setSelectedOption(idx); } }} 
                                    className={`w-full p-4 rounded-xl border-2 text-left text-lg font-medium transition-all active:scale-95 
                                        ${showResult && idx === currentStep.correct ? 'bg-green-100 border-green-500 text-green-700' : ''} 
                                        ${showResult && idx === selectedOption && idx !== currentStep.correct ? 'bg-red-100 border-red-500 text-red-700' : ''} 
                                        ${!showResult && selectedOption === idx ? 'bg-blue-100 border-blue-500 text-blue-700' : 'bg-white border-gray-200 hover:bg-gray-50'}`}
                                >
                                    {opt}
                                </button>
                            ))}
                        </div>
                    </div>
                )}
                {currentStep.type === 'match' && <div className="w-full"><h2 className="text-2xl font-bold mb-6 text-gray-800">{currentStep.question}</h2><MatchGame step={currentStep} onCorrect={handleMatchComplete} /></div>}
                {currentStep.type === 'fill' && <div className="w-full"><h2 className="text-2xl font-bold mb-6 text-gray-800">{currentStep.question}</h2><FillBlank step={currentStep} selectedIdx={selectedOption} showResult={showResult} isCorrect={isCorrect} onSelect={(idx) => setSelectedOption(idx)} /></div>}
            </div>

            <div className="absolute top-20 right-4"><button onClick={() => { SoundSynth.play('pop'); setShowSensei(true); }} className="bg-indigo-100 text-indigo-600 w-10 h-10 rounded-full flex items-center justify-center hover:bg-indigo-200 shadow-sm border border-indigo-200 transition-transform hover:scale-110 active:scale-90" title="Ask AI Sensei"><i className="fa-solid fa-robot"></i></button></div>

            {showSensei && <ChatSensei context={currentStep.type === 'theory' || currentStep.type === 'boss' ? (currentStep.content || "") : (currentStep.question || "")} onClose={() => setShowSensei(false)} />}

            <div className={`p-4 border-t transition-colors duration-300 ${showResult ? (isCorrect ? 'bg-green-100 border-green-300' : 'bg-red-100 border-red-300') : 'bg-white'}`}>
                <div className="max-w-2xl mx-auto flex justify-between items-center">
                    {showResult && (
                        <div className="flex gap-3 items-center animate-pop">
                            <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white ${isCorrect ? 'bg-green-500' : 'bg-red-500'}`}>
                                <i className={`fa-solid ${isCorrect ? 'fa-check' : 'fa-xmark'}`}></i>
                            </div>
                            <div className={`font-bold ${isCorrect ? 'text-green-700' : 'text-red-700'}`}>
                                {isCorrect ? "正确！" : `错误，正确答案是: ${currentStep.type === 'quiz' ? currentStep.options![Number(currentStep.correct)] : currentStep.correct}`}
                            </div>
                        </div>
                    )}
                    <div className="flex-1"></div>
                    {(currentStep.type === 'quiz' || currentStep.type === 'fill') && !showResult ? (
                        <button 
                            onClick={handleCheck} 
                            disabled={selectedOption === null} 
                            className="px-8 py-3 rounded-xl font-bold text-white uppercase tracking-wide shadow-lg btn-press bg-green-500 hover:bg-green-600 disabled:opacity-50"
                        >
                            检查
                        </button>
                    ) : (currentStep.type === 'theory' || currentStep.type === 'boss' || showResult) ? (
                        <button 
                            onClick={handleContinue} 
                            className={`px-8 py-3 rounded-xl font-bold text-white uppercase tracking-wide shadow-lg btn-press ${showResult && !isCorrect ? 'bg-red-500 hover:bg-red-600' : 'bg-green-500 hover:bg-green-600'}`}
                        >
                            继续
                        </button>
                    ) : null}
                </div>
            </div>
        </div>
    );
};

