// --- Confetti Component ---
const Confetti = () => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    const particles: any[] = [];
    const colors = ['#EF4444', '#F59E0B', '#10B981', '#3B82F6', '#8B5CF6'];
    for (let i = 0; i < 100; i++) {
      particles.push({
        x: window.innerWidth / 2, y: window.innerHeight / 2,
        color: colors[Math.floor(Math.random() * colors.length)],
        v: { x: (Math.random() - 0.5) * 15, y: (Math.random() - 0.5) * 15 - 5 },
        spin: Math.random() * 0.2 - 0.1
      });
    }
    let animationId: number;
    const render = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      particles.forEach((p, i) => {
        p.x += p.v.x; p.y += p.v.y; p.v.y += 0.2; p.v.x *= 0.96;
        ctx.save(); ctx.translate(p.x, p.y); ctx.rotate(p.spin * i);
        ctx.fillStyle = p.color; ctx.fillRect(-5, -5, 10, 10); ctx.restore();
      });
      if (particles.some(p => p.y < canvas.height)) animationId = requestAnimationFrame(render);
    };
    render();
    return () => cancelAnimationFrame(animationId);
  }, []);
  return <canvas ref={canvasRef} className="fixed inset-0 pointer-events-none z-[70]" />;
};

