                    <span key={i} className={`border-b-4 px-2 font-bold min-w-[80px] text-center transition-colors ${showResult ? (isCorrect ? 'border-green-500 text-green-600' : 'border-red-500 text-red-600 line-through') : 'border-gray-300 text-indigo-600'}`}>{selectedText || "____"}</span>
                ) : <span key={i}>{part}</span>)}
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">{step.options?.map((opt, idx) => (
                <button 
                  key={idx} 
                  onClick={() => { if(!showResult) { SoundSynth.play('pop'); onSelect(idx); } }} 
                  className={`p-4 rounded-xl border-b-4 font-bold text-lg transition-all active:translate-y-1 active:border-b-0 
                    ${selectedIdx === idx ? 'bg-indigo-100 border-indigo-400 text-indigo-700' : 'bg-white border-gray-300 text-gray-700 hover:bg-gray-50'}
                    ${showResult && opt === step.correct ? 'bg-green-100 border-green-500 text-green-700' : ''}
                    ${showResult && selectedIdx === idx && opt !== step.correct ? 'bg-red-100 border-red-500 text-red-700' : ''}
