// --- Lesson Engine (Summary Implementation) ---
const LessonEngine = ({ weekId, dayId, onComplete, onExit }: { weekId: number, dayId: number, onComplete: () => void, onExit: () => void }) => {
    const lessonData = ALL_CURRICULUM[weekId]?.find(d => d.day === dayId);
    const [stepIndex, setStepIndex] = useState(0);
    const [selectedOption, setSelectedOption] = useState<number | null>(null);
    const [showResult, setShowResult] = useState(false);
    const [isCorrect, setIsCorrect] = useState(false);
    const [showSensei, setShowSensei] = useState(false);

    if (!lessonData) return null;
    const currentStep = lessonData.steps[stepIndex];

    const handleCheck = () => {
        let correct = false;
        if (currentStep.type === 'quiz') correct = selectedOption === currentStep.correct;
        else if (currentStep.type === 'fill') correct = currentStep.options![selectedOption!] === currentStep.correct;
        setIsCorrect(correct); setShowResult(true);
        if (correct) SoundSynth.play('correct'); else SoundSynth.play('wrong');
    };

    const handleContinue = () => {
        SoundSynth.play('pop');
        if (stepIndex < lessonData.steps.length - 1) {
            setStepIndex(prev => prev + 1); setSelectedOption(null); setShowResult(false);
        } else {
            onComplete();
        }
    };

    return (
        <div className="fixed inset-0 bg-white z-50 flex flex-col">
            <div className="p-4 flex items-center gap-4"><button onClick={onExit} className="text-gray-400"><i className="fa-solid fa-xmark text-2xl"></i></button><ProgressBar current={stepIndex+1} total={lessonData.steps.length}/></div>
            <div className="flex-1 flex flex-col items-center justify-center p-6 max-w-2xl mx-auto w-full overflow-y-auto">
                {currentStep.type === 'video' && <div className="w-full aspect-video bg-black rounded-2xl overflow-hidden mb-4"><iframe src={currentStep.url} className="w-full h-full" allowFullScreen></iframe></div>}
                {(currentStep.type === 'theory' || currentStep.type === 'boss') && <div className="text-center"><h2 className="text-2xl font-bold mb-4">{currentStep.content}</h2><i className={`fa-solid ${currentStep.isBoss ? 'fa-dragon text-red-500' : 'fa-lightbulb text-orange-400'} text-6xl animate-bounce-slight`}></i></div>}
                {currentStep.type === 'quiz' && <div className="w-full"><h2 className="text-2xl font-bold mb-6">{currentStep.question}</h2>{currentStep.options?.map((opt, i) => <button key={i} onClick={() => setSelectedOption(i)} className={`w-full p-4 mb-3 border-2 rounded-xl text-left ${selectedOption === i ? 'border-indigo-500 bg-indigo-50' : 'border-gray-200'}`}>{opt}</button>)}</div>}
                {currentStep.type === 'match' && <MatchGame step={currentStep} onCorrect={() => { setIsCorrect(true); setShowResult(true); SoundSynth.play('correct'); }}/>}
                {currentStep.type === 'fill' && <FillBlank step={currentStep} selectedIdx={selectedOption} showResult={showResult} isCorrect={isCorrect} onSelect={setSelectedOption}/>}
            </div>
            <button onClick={() => setShowSensei(true)} className="absolute top-20 right-4 w-12 h-12 rounded-full bg-indigo-100 flex items-center justify-center shadow-lg"><i className="fa-solid fa-robot text-indigo-600"></i></button>
            {showSensei && <ChatSensei context={currentStep.question || currentStep.content || ""} onClose={() => setShowSensei(false)}/>}
            <div className={`p-6 border-t ${showResult ? (isCorrect ? 'bg-green-100' : 'bg-red-100') : 'bg-white'}`}>
                <div className="max-w-2xl mx-auto flex justify-between items-center">
                    {showResult ? <div className={`font-bold ${isCorrect ? 'text-green-700' : 'text-red-700'}`}>{isCorrect ? "干得漂亮！" : "哎呀，再想想！"}</div> : <div></div>}
                    {!showResult && (currentStep.type === 'quiz' || currentStep.type === 'fill') ? <button onClick={handleCheck} disabled={selectedOption === null} className="bg-green-500 text-white px-8 py-3 rounded-xl font-bold shadow-lg disabled:opacity-50">检查</button> : <button onClick={handleContinue} className="bg-green-500 text-white px-8 py-3 rounded-xl font-bold shadow-lg">继续</button>}
                </div>
            </div>
        </div>
    );
};

// --- App Root ---
const App = () => {
  const [showSplash, setShowSplash] = useState(true);
  const [view, setView] = useState<'world' | 'week' | 'lesson'>('world');
  const [selectedWeekId, setSelectedWeekId] = useState<number | null>(null);
  const [selectedDayId, setSelectedDayId] = useState<number | null>(null);
  const [unlockedWeek, setUnlockedWeek] = useState(1);
  const [collectedBalls, setCollectedBalls] = useState(0);
  const [completedDays, setCompletedDays] = useState(0);
  const [showConfetti, setShowConfetti] = useState(false);
  const [showGlossary, setShowGlossary] = useState(false);

  const handleUnlockAll = () => { setUnlockedWeek(7); setCollectedBalls(7); setCompletedDays(7); setShowConfetti(true); setTimeout(() => setShowConfetti(false), 3000); };
  const handleLessonComplete = () => {
    if (selectedWeekId === 1 && selectedDayId === completedDays + 1) {
        setCompletedDays(prev => prev + 1);
        if (completedDays + 1 === ALL_CURRICULUM[1].length) {
            setCollectedBalls(prev => Math.min(prev + 1, 7));
            setUnlockedWeek(prev => prev + 1);
            setShowConfetti(true); setTimeout(() => setShowConfetti(false), 5000);
        }
    }
    setView('week');
  };

  return (
    <div className="font-sans bg-gray-50 min-h-screen select-none text-gray-900">
        {showSplash && <SplashScreen onFinish={() => setShowSplash(false)} />}
        {!showSplash && (
          <>
            {showConfetti && <Confetti />}
            {showGlossary && <GlossaryView onClose={() => setShowGlossary(false)} />}
            {view === 'world' && <WorldMap unlockedWeek={unlockedWeek} onSelectWeek={(id) => { setSelectedWeekId(id); setView('week'); }} collectedBalls={collectedBalls} onUnlockAll={handleUnlockAll} />}
            {view === 'week' && selectedWeekId && <WeekLevelView weekId={selectedWeekId} completedDays={completedDays} onPlayDay={(day) => { setSelectedDayId(day); setView('lesson'); }} onBack={() => setView('world')} onOpenGlossary={() => setShowGlossary(true)} />}
            {view === 'lesson' && selectedWeekId && selectedDayId && <LessonEngine weekId={selectedWeekId} dayId={selectedDayId} onComplete={handleLessonComplete} onExit={() => setView('week')} />}
          </>
        )}
    </div>
  );
};

