    SoundSynth.play('pop');
    setIsFlipped(false);
    setCurrentIndex((prev) => (prev + 1) % AI_GLOSSARY.length);
  };

  const handlePrev = () => {
    SoundSynth.play('pop');
    setIsFlipped(false);
    setCurrentIndex((prev) => (prev - 1 + AI_GLOSSARY.length) % AI_GLOSSARY.length);
  };

  const handleFlip = () => {
    SoundSynth.play('flip');
    setIsFlipped(!isFlipped);
  };

