                    <div className="bg-white/90 px-6 py-2 rounded-full shadow-lg border-2 border-yellow-200 flex items-center gap-3">
                        <span className="text-orange-600 font-bold flex items-center gap-2 text-xl"><i className="fa-solid fa-dragon"></i> {collectedBalls}/7 龙珠</span>
                    </div>
                </div>
                <button onClick={handleUnlockAll} className="absolute top-4 right-4 bg-white/20 text-white px-3 py-1 rounded-full text-xs font-bold border border-white/40">一键解锁</button>
                <div className="flex-1 w-full max-w-sm flex flex-col justify-around py-8 px-10">
                    {WEEKS.map((week, idx) => (
                        <div key={week.id} className={`flex w-full ${idx % 2 === 0 ? 'justify-start' : 'justify-end'}`}>
                            <LevelMarker isUnlocked={week.id <= unlockedWeek} isCompleted={week.id < unlockedWeek} icon={week.icon === 'fa-magnifying-glass' ? 'fa-house' : week.icon} weekTitle={week.title} onClick={() => week.id <= unlockedWeek && (setSelectedWeekId(week.id), setView('week'), SoundSynth.play('pop'))} />
                        </div>
                    ))}
                </div>
            </div>}

            {view === 'week' && selectedWeekId && <div className="min-h-screen bg-[#3f64e7] flex flex-col relative overflow-hidden">
                <div className="p-4 flex items-center justify-between text-white z-10">
                    <div className="flex items-center gap-4">
                        <button onClick={() => setView('world')} className="p-2 bg-white/10 rounded-full"><i className="fa-solid fa-arrow-left"></i></button>
                        <h2 className="text-xl font-bold">{WEEKS.find(w=>w.id===selectedWeekId)?.title}</h2>
                    </div>
                    {selectedWeekId === 1 && <button onClick={() => setShowGlossary(true)} className="bg-yellow-400 text-indigo-900 px-4 py-2 rounded-2xl font-bold shadow-lg flex items-center gap-2 animate-bounce-slight"><i className="fa-solid fa-book-sparkles"></i> 名词本</button>}
                </div>
                <div className="flex-1 flex flex-col items-center justify-center gap-8 py-20">
                    {(ALL_CURRICULUM[selectedWeekId] || []).map((day, idx) => {
                        const isUnlocked = idx <= currentCompletedDays;
                        const isDone = idx < currentCompletedDays;
                        return (
                            <div key={day.day} className={`relative transition-all ${idx % 2 === 0 ? '-translate-x-12' : 'translate-x-12'} animate-pop`} style={{animationDelay: `${idx*0.1}s`}}>
                                <button onClick={() => isUnlocked && (setSelectedDayId(day.day), setView('lesson'), SoundSynth.play('pop'))} className={`w-20 h-20 rounded-full border-b-8 flex items-center justify-center text-2xl shadow-xl transition-all active:translate-y-1 active:border-b-0 ${isDone ? 'bg-yellow-400 border-yellow-600 text-yellow-900' : isUnlocked ? 'bg-orange-500 border-orange-700 text-white animate-bounce-slight' : 'bg-gray-400 border-gray-600 text-gray-200'}`}>
                                    {isDone ? <i className="fa-solid fa-check"></i> : isUnlocked ? <i className="fa-solid fa-star"></i> : <i className="fa-solid fa-lock"></i>}
