            </div>}

            {view === 'lesson' && selectedWeekId && selectedDayId && <LessonEngine weekId={selectedWeekId} dayId={selectedDayId} onComplete={handleLessonComplete} onExit={() => setView('week')} />}
          </>
        )}
    </div>
  );
};

