            </div>
          </div>

          <div className="flex gap-4 sm:gap-8 mt-10">
            <button onClick={(e) => { e.stopPropagation(); handlePrev(); }} className="w-12 h-12 sm:w-14 sm:h-14 rounded-full bg-white/20 text-white flex items-center justify-center hover:bg-white/30"><i className="fa-solid fa-chevron-left"></i></button>
            <button onClick={(e) => { e.stopPropagation(); startQuiz(); }} className="px-6 py-2 rounded-full bg-yellow-400 text-indigo-900 font-bold hover:bg-yellow-300 shadow-lg flex items-center gap-2 text-sm sm:text-base">随机抽查</button>
            <button onClick={(e) => { e.stopPropagation(); handleNext(); }} className="w-12 h-12 sm:w-14 sm:h-14 rounded-full bg-white/20 text-white flex items-center justify-center hover:bg-white/30"><i className="fa-solid fa-chevron-right"></i></button>
          </div>
          <p className="mt-6 text-white/50 text-sm">{currentIndex + 1} / {AI_GLOSSARY.length}</p>
