      ) : (
        <div className="w-full max-w-sm bg-white rounded-3xl p-8 shadow-2xl animate-pop relative overflow-hidden">
          <h2 className="text-xl font-bold text-gray-800 mb-6 text-center">这是什么的定义？</h2>
