                <i className="fa-solid fa-cloud absolute top-[45%] left-0 text-white/30 text-8xl animate-float-cloud-slow z-0" style={{ animationDelay: '-10s' }}></i>
                <i className="fa-solid fa-cloud absolute top-[60%] left-0 text-white/25 text-5xl animate-float-cloud z-0" style={{ animationDelay: '-22s' }}></i>
                <i className="fa-solid fa-cloud absolute top-[78%] left-0 text-white/50 text-5xl animate-float-cloud z-0" style={{ animationDelay: '-5s' }}></i>
