                </div>
                <button 
                  onClick={handleQuizFinish} 
                  className={`w-full py-3 rounded-xl font-bold text-white shadow-lg active:scale-95 transition-transform ${quizResult.correct ? 'bg-green-500' : 'bg-red-500'}`}
